do $$
declare
  child_count int;
  parent_count int;
  set_count int;
  unsupported_finish_count int;
  existing_child_count int;
  id_collision_count int;
begin
  select count(*) into child_count from pkg06g_active_child_printings;
  select count(distinct card_print_id) into parent_count from pkg06g_active_child_printings;
  select count(distinct set_key) into set_count from pkg06g_active_child_printings;
  select count(*) into unsupported_finish_count
  from pkg06g_active_child_printings target
  left join public.finish_keys fk
    on fk.key = target.finish_key
   and fk.is_active = true
  where fk.key is null;
  select count(*) into existing_child_count
  from pkg06g_active_child_printings target
  join public.card_printings cpr
    on cpr.card_print_id = target.card_print_id
   and cpr.finish_key = target.finish_key;
  select count(*) into id_collision_count
  from pkg06g_active_child_printings target
  join public.card_printings cpr on cpr.id = target.card_printing_id;

  if child_count <> 313 then raise exception 'PKG-06G child count drift: %', child_count; end if;
  if parent_count <> 305 then raise exception 'PKG-06G parent count drift: %', parent_count; end if;
  if set_count <> 10 then raise exception 'PKG-06G set count drift: %', set_count; end if;
  if unsupported_finish_count <> 0 then raise exception 'PKG-06G unsupported finish count: %', unsupported_finish_count; end if;
  if existing_child_count <> 0 then raise exception 'PKG-06G existing child count: %', existing_child_count; end if;
  if id_collision_count <> 0 then raise exception 'PKG-06G id collision count: %', id_collision_count; end if;
end $$;

insert into public.card_printings (
  id,
  card_print_id,
  finish_key,
  is_provisional,
  provenance_source,
  provenance_ref,
  created_by
)
select
  card_printing_id,
  card_print_id,
  finish_key,
  false,
  provenance_source,
  provenance_ref,
  created_by
from pkg06g_active_child_printings;

select
  'PKG-06G-ACTIVE-FINISH-CHILD-PRINTING-INSERTS'::text as package_id,
  '3024e09ed58f58fddaaf5ce1e7fe99e0afec2ced46b741b527776b762feb965d'::text as source_readiness_fingerprint,
  '4218f824485c51703e3428dbd1e8e5dcacabe0490242500cc3d803efdfd7baad'::text as package_fingerprint,
  (select count(distinct set_key) from pkg06g_active_child_printings)::int as planned_sets,
  (select count(distinct card_print_id) from pkg06g_active_child_printings)::int as target_parent_rows,
  (select count(*) from pkg06g_active_child_printings)::int as planned_child_rows;

rollback;
